const setup = $('⚙️ Setup').first().json;
const urls = (setup.KONKURRENT_URLS || '').split(',').map(u => u.trim()).filter(u => u.startsWith('http'));
return urls.map(url => ({ json: { url } }));

const url = $('🔗 URLs aufteilen').item.json.url;
const html = ($json.data || '').toString();
// HTML grob zu Text eindampfen, damit der Prompt klein bleibt
const text = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .slice(0, 12000);

const prompt = 'Hier der Textinhalt einer Produktseite eines Konkurrenten (' + url + '):\n\n' + text + '\n\n' +
  'Extrahiere: Produktname und aktueller Verkaufspreis (der Preis, den ein Kunde JETZT zahlen wuerde - bei Streichpreisen der reduzierte). Falls ein Rabatt/Sale erkennbar ist, nenne ihn.\n' +
  'Antworte NUR mit validem JSON, ohne Markdown-Codeblock: {"produkt": "...", "preis": "29.99", "waehrung": "EUR", "sale": "ja|nein", "sale_info": "..."}\n' +
  'Wenn kein Preis erkennbar ist: {"produkt": "unbekannt", "preis": "", "waehrung": "", "sale": "nein", "sale_info": ""}';

return { json: { url, prompt } };

const sd = $getWorkflowStaticData('global');
sd.preise = sd.preise || {};
const eingaben = $('🧠 Seite aufbereiten').all();
const antworten = $input.all();
const zeilen = [];
let alarm = false;

for (let i = 0; i < antworten.length; i++) {
  const url = (eingaben[i] || { json: {} }).json.url || '?';
  const blocks = antworten[i].json.content || [];
  const text = (blocks.find(b => b.type === 'text') || {}).text || '';
  let d;
  try { d = JSON.parse(text.replace(/```json|```/g, '').trim()); }
  catch (e) { d = { produkt: 'unbekannt', preis: '', sale: 'nein', sale_info: '' }; }

  const alt = sd.preise[url];
  const neu = d.preis;
  let zeile = '• ' + d.produkt + '\n  ' + (neu ? neu + ' ' + (d.waehrung || '') : 'Preis nicht lesbar');

  if (alt && neu && alt !== neu) {
    const altF = parseFloat(alt); const neuF = parseFloat(neu);
    const pfeil = neuF < altF ? '📉 GESENKT' : '📈 ERHOEHT';
    zeile += '\n  ⚡ ' + pfeil + ': vorher ' + alt + ' -> jetzt ' + neu;
    alarm = true;
  }
  if (d.sale === 'ja') { zeile += '\n  🔥 SALE: ' + (d.sale_info || 'aktiv'); alarm = true; }
  zeile += '\n  ' + url;
  zeilen.push(zeile);
  if (neu) sd.preise[url] = neu;
}

const setup = $('⚙️ Setup').first().json;
const kopf = (alarm ? '🚨 PREIS-SPION: BEWEGUNG BEI DER KONKURRENZ!' : '🕵️ PREIS-SPION: Alles ruhig.') + '\n' + setup.SHOP_NAME + '\n━━━━━━━━━━━━━━━━━━\n\n';
return [{ json: { telegram_text: kopf + zeilen.join('\n\n') } }];
